import { formatDistanceToNow } from "date-fns";
import { RefreshCw, AlertCircle, TrendingUp, TrendingDown } from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";
import { Button } from "@/components/ui/button";
import { Alert, AlertDescription } from "@/components/ui/alert";
import Gauge from "./components/Gauge";
import TrendChart from "./components/TrendChart";
import { useFearGreed } from "./hooks/useFearGreed";

function LoadingSkeleton() {
  return (
    <div className="w-full h-full p-4 space-y-4">
      <div className="flex justify-center">
        <Skeleton className="w-[380px] h-[200px] bg-zinc-800" />
      </div>
      <div className="flex justify-center gap-2">
        <Skeleton className="w-16 h-6 bg-zinc-800" />
        <Skeleton className="w-24 h-6 bg-zinc-800" />
      </div>
      <Skeleton className="w-full h-[120px] bg-zinc-800" />
    </div>
  );
}

function getChangeInfo(history: { value: number }[]) {
  if (history.length < 2) return null;
  const current = history[0].value;
  const yesterday = history[1].value;
  const change = current - yesterday;
  return { change, yesterday };
}

export default function App() {
  const { current, history, loading, error, lastUpdated, refresh } = useFearGreed();

  if (loading) return <LoadingSkeleton />;

  if (error) {
    return (
      <div className="w-full h-full overflow-auto p-4 space-y-4">
        <Alert variant="destructive" className="bg-red-950/50 border-red-900">
          <AlertCircle className="h-4 w-4" />
          <AlertDescription className="text-zinc-300">
            {error}
          </AlertDescription>
        </Alert>
        <div className="flex justify-center">
          <Button
            variant="outline"
            size="sm"
            onClick={refresh}
            className="text-zinc-300 border-zinc-700"
          >
            <RefreshCw className="w-3 h-3 mr-2" />
            Retry
          </Button>
        </div>
      </div>
    );
  }

  if (!current) return null;

  const changeInfo = getChangeInfo(history);

  return (
    <div className="w-full h-full overflow-auto p-4 space-y-3">
      {/* Gauge */}
      <Gauge value={current.value} classification={current.value_classification} />

      {/* Change from yesterday + refresh */}
      <div className="flex items-center justify-between px-1">
        <div className="flex items-center gap-3">
          {changeInfo && (
            <div className="flex items-center gap-1.5 text-xs font-mono">
              {changeInfo.change > 0 ? (
                <TrendingUp className="w-3.5 h-3.5 text-emerald-400" />
              ) : changeInfo.change < 0 ? (
                <TrendingDown className="w-3.5 h-3.5 text-red-400" />
              ) : null}
              <span
                className={
                  changeInfo.change > 0
                    ? "text-emerald-400"
                    : changeInfo.change < 0
                    ? "text-red-400"
                    : "text-zinc-400"
                }
              >
                {changeInfo.change > 0 ? "+" : ""}
                {changeInfo.change}
              </span>
              <span className="text-zinc-600">vs yesterday ({changeInfo.yesterday})</span>
            </div>
          )}
        </div>
        <div className="flex items-center gap-2">
          {lastUpdated && (
            <span className="text-[10px] text-zinc-600 font-mono">
              {formatDistanceToNow(lastUpdated, { addSuffix: true })}
            </span>
          )}
          <button
            onClick={refresh}
            className="text-zinc-500 hover:text-zinc-300 transition-colors p-1"
            title="Refresh"
          >
            <RefreshCw className="w-3.5 h-3.5" />
          </button>
        </div>
      </div>

      {/* Separator */}
      <div className="border-t border-zinc-800" />

      {/* Trend chart */}
      <TrendChart data={history} />
    </div>
  );
}

