import { useEffect, useRef, useState } from "react";

interface GaugeProps {
  value: number;
  classification: string;
}

const ZONES = [
  { start: 0, end: 25, color: "#ef4444", label: "Extreme Fear" },
  { start: 25, end: 45, color: "#f97316", label: "Fear" },
  { start: 45, end: 55, color: "#eab308", label: "Neutral" },
  { start: 55, end: 75, color: "#4ade80", label: "Greed" },
  { start: 75, end: 100, color: "#22c55e", label: "Extreme Greed" },
];

function valueToAngle(value: number): number {
  // Map 0-100 to -180° to 0° (left to right semicircle)
  return -180 + (value / 100) * 180;
}

function polarToCartesian(cx: number, cy: number, r: number, angleDeg: number) {
  const rad = (angleDeg * Math.PI) / 180;
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  };
}

function describeArc(cx: number, cy: number, r: number, startAngle: number, endAngle: number) {
  const start = polarToCartesian(cx, cy, r, endAngle);
  const end = polarToCartesian(cx, cy, r, startAngle);
  const largeArc = endAngle - startAngle > 180 ? 1 : 0;
  return `M ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y}`;
}

function getColorForValue(value: number): string {
  for (const zone of ZONES) {
    if (value >= zone.start && value < zone.end) return zone.color;
  }
  return ZONES[ZONES.length - 1].color;
}

export default function Gauge({ value, classification }: GaugeProps) {
  const [animatedValue, setAnimatedValue] = useState(0);
  const animRef = useRef<number>();

  useEffect(() => {
    const start = animatedValue;
    const end = value;
    const duration = 1200;
    const startTime = performance.now();

    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setAnimatedValue(start + (end - start) * eased);
      if (progress < 1) {
        animRef.current = requestAnimationFrame(animate);
      }
    };

    animRef.current = requestAnimationFrame(animate);
    return () => {
      if (animRef.current) cancelAnimationFrame(animRef.current);
    };
  }, [value]);

  const cx = 200;
  const cy = 190;
  const outerR = 160;
  const innerR = 120;
  const needleR = 130;

  const needleAngle = valueToAngle(animatedValue);
  const needleTip = polarToCartesian(cx, cy, needleR, needleAngle);
  const needleBaseL = polarToCartesian(cx, cy, 8, needleAngle - 90);
  const needleBaseR = polarToCartesian(cx, cy, 8, needleAngle + 90);

  return (
    <div className="flex flex-col items-center w-full">
      <svg viewBox="0 0 400 230" className="w-full max-w-[420px]">
        <defs>
          <filter id="glow">
            <feGaussianBlur stdDeviation="3" result="coloredBlur" />
            <feMerge>
              <feMergeNode in="coloredBlur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
          <filter id="needleShadow">
            <feDropShadow dx="0" dy="1" stdDeviation="2" floodColor="#000" floodOpacity="0.5" />
          </filter>
        </defs>

        {/* Background track */}
        <path
          d={describeArc(cx, cy, (outerR + innerR) / 2, -180, 0)}
          fill="none"
          stroke="#27272a"
          strokeWidth={outerR - innerR}
          strokeLinecap="butt"
        />

        {/* Colored zone arcs */}
        {ZONES.map((zone) => {
          const startA = -180 + (zone.start / 100) * 180;
          const endA = -180 + (zone.end / 100) * 180;
          return (
            <path
              key={zone.label}
              d={describeArc(cx, cy, (outerR + innerR) / 2, startA, endA)}
              fill="none"
              stroke={zone.color}
              strokeWidth={outerR - innerR}
              strokeLinecap="butt"
              opacity={0.85}
            />
          );
        })}

        {/* Tick marks */}
        {Array.from({ length: 21 }).map((_, i) => {
          const val = i * 5;
          const angle = valueToAngle(val);
          const isMajor = val % 25 === 0;
          const outer = polarToCartesian(cx, cy, outerR + 2, angle);
          const inner = polarToCartesian(cx, cy, outerR + (isMajor ? 14 : 8), angle);
          return (
            <g key={i}>
              <line
                x1={outer.x}
                y1={outer.y}
                x2={inner.x}
                y2={inner.y}
                stroke="#71717a"
                strokeWidth={isMajor ? 2 : 1}
              />
              {isMajor && (
                <text
                  x={polarToCartesian(cx, cy, outerR + 26, angle).x}
                  y={polarToCartesian(cx, cy, outerR + 26, angle).y}
                  fill="#a1a1aa"
                  fontSize="11"
                  textAnchor="middle"
                  dominantBaseline="middle"
                  fontFamily="monospace"
                >
                  {val}
                </text>
              )}
            </g>
          );
        })}

        {/* Needle */}
        <polygon
          points={`${needleTip.x},${needleTip.y} ${needleBaseL.x},${needleBaseL.y} ${needleBaseR.x},${needleBaseR.y}`}
          fill="#f4f4f5"
          filter="url(#needleShadow)"
        />

        {/* Center circle */}
        <circle cx={cx} cy={cy} r={12} fill="#3f3f46" stroke="#52525b" strokeWidth={2} />
        <circle cx={cx} cy={cy} r={5} fill="#a1a1aa" />

        {/* Center value text */}
        <text
          x={cx}
          y={cy - 30}
          fill={getColorForValue(value)}
          fontSize="48"
          fontWeight="bold"
          textAnchor="middle"
          dominantBaseline="auto"
          fontFamily="monospace"
          filter="url(#glow)"
        >
          {Math.round(animatedValue)}
        </text>

        {/* Classification text */}
        <text
          x={cx}
          y={cy + 5}
          fill="#e4e4e7"
          fontSize="15"
          textAnchor="middle"
          dominantBaseline="hanging"
          fontFamily="monospace"
          letterSpacing="0.05em"
        >
          {classification}
        </text>

        {/* Labels at extremes */}
        <text x={30} y={cy + 20} fill="#ef4444" fontSize="10" fontFamily="monospace" opacity={0.7}>
          EXTREME FEAR
        </text>
        <text x={310} y={cy + 20} fill="#22c55e" fontSize="10" fontFamily="monospace" opacity={0.7}>
          EXTREME GREED
        </text>
      </svg>
    </div>
  );
}

