import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  Cell,
  ReferenceLine,
} from "recharts";
import { format } from "date-fns";

interface DataPoint {
  value: number;
  value_classification: string;
  timestamp: string;
  date: string;
}

interface TrendChartProps {
  data: DataPoint[];
}

function getBarColor(value: number): string {
  if (value < 25) return "#ef4444";
  if (value < 45) return "#f97316";
  if (value < 55) return "#eab308";
  if (value < 75) return "#4ade80";
  return "#22c55e";
}

const CustomTooltip = ({ active, payload }: any) => {
  if (!active || !payload?.length) return null;
  const d = payload[0].payload;
  return (
    <div className="bg-zinc-800 border border-zinc-700 px-3 py-2 text-xs font-mono">
      <div className="text-zinc-300">{d.date}</div>
      <div className="mt-1" style={{ color: getBarColor(d.value) }}>
        <span className="font-bold text-sm">{d.value}</span>
        <span className="ml-2 text-zinc-400">{d.value_classification}</span>
      </div>
    </div>
  );
};

export default function TrendChart({ data }: TrendChartProps) {
  // Data comes newest first, reverse for chart (oldest on left)
  const chartData = [...data].reverse();

  return (
    <div className="w-full">
      <div className="text-xs text-zinc-500 font-mono mb-2 uppercase tracking-wide">
        30-Day Trend
      </div>
      <div className="w-full h-[120px]">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={chartData} margin={{ top: 4, right: 4, bottom: 0, left: -20 }}>
            <XAxis
              dataKey="date"
              tick={{ fill: "#71717a", fontSize: 9, fontFamily: "monospace" }}
              tickLine={false}
              axisLine={{ stroke: "#3f3f46" }}
              interval={Math.floor(chartData.length / 5)}
            />
            <YAxis
              domain={[0, 100]}
              tick={{ fill: "#71717a", fontSize: 9, fontFamily: "monospace" }}
              tickLine={false}
              axisLine={false}
              ticks={[0, 25, 50, 75, 100]}
            />
            <Tooltip
              content={<CustomTooltip />}
              cursor={{ fill: "rgba(255,255,255,0.05)" }}
            />
            <ReferenceLine y={50} stroke="#3f3f46" strokeDasharray="3 3" />
            <Bar dataKey="value" radius={[2, 2, 0, 0]} maxBarSize={14}>
              {chartData.map((entry, index) => (
                <Cell key={index} fill={getBarColor(entry.value)} fillOpacity={0.85} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

